import{_ as a,o as e,c as t,aw as i}from"./chunks/framework.Dq2onT5h.js";const s=JSON.parse('{"title":"Attester Node","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Attester Node | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/running-nodes/attester.md","filePath":"guides/running-nodes/attester.md","lastUpdated":1772446570000}');const n=a({name:"guides/running-nodes/attester.md"},[["render",function(a,s,n,l,o,r){return e(),t("div",null,[...s[0]||(s[0]=[i('<h1 id="attester-node" tabindex="-1">Attester Node <a class="header-anchor" href="#attester-node" aria-label="Permalink to &quot;Attester Node&quot;">​</a></h1><p>Attester nodes participate in the validator network to provide faster soft finality through attestations. This is an advanced feature for chains requiring sub-DA-finality confirmation times.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Attesters:</p><ul><li>Validate blocks produced by the aggregator</li><li>Sign attestations confirming block validity</li><li>Participate in a soft consensus protocol</li><li>Enable faster finality than DA-only confirmation</li></ul><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>The attester network feature is under active development. This documentation will be updated as the feature matures.</p><p>For technical details on the validator network design, see <a href="https://github.com/evstack/ev-node/blob/main/specs/src/adr/adr-022-validator-network.md" target="_blank" rel="noreferrer">ADR-022: Validator Network</a>.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><h3 id="soft-finality" tabindex="-1">Soft Finality <a class="header-anchor" href="#soft-finality" aria-label="Permalink to &quot;Soft Finality&quot;">​</a></h3><p>Without attesters, finality depends on DA confirmation (~6-12 seconds for Celestia). With an attester network:</p><ol><li>Aggregator produces block</li><li>Attesters validate and sign attestations</li><li>When threshold of attestations collected, block has soft finality</li><li>DA finality provides hard finality later</li></ol><h3 id="trust-model" tabindex="-1">Trust Model <a class="header-anchor" href="#trust-model" aria-label="Permalink to &quot;Trust Model&quot;">​</a></h3><ul><li>Soft finality requires trusting the attester set (configurable threshold)</li><li>Hard finality (DA) remains trustless</li><li>Applications can choose which finality level to wait for</li></ul><h2 id="configuration-preview" tabindex="-1">Configuration (Preview) <a class="header-anchor" href="#configuration-preview" aria-label="Permalink to &quot;Configuration (Preview)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run as attester (preview configuration)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.attester</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.address</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:26658</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.p2p.peers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /ip4/sequencer.example.com/tcp/7676/p2p/12D3KooW...</span></span></code></pre></div><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="low-latency-applications" tabindex="-1">Low-Latency Applications <a class="header-anchor" href="#low-latency-applications" aria-label="Permalink to &quot;Low-Latency Applications&quot;">​</a></h3><p>Applications requiring confirmation faster than DA finality:</p><ul><li>Trading platforms</li><li>Gaming</li><li>Real-time settlement</li></ul><h3 id="enhanced-security" tabindex="-1">Enhanced Security <a class="header-anchor" href="#enhanced-security" aria-label="Permalink to &quot;Enhanced Security&quot;">​</a></h3><p>Additional validation layer before DA confirmation:</p><ul><li>Multi-party validation</li><li>Early fraud detection</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/concepts/finality">Finality Concepts</a> - Understanding finality in Evolve</li><li><a href="/guides/running-nodes/full-node">Full Node Guide</a> - Running a full node</li></ul>',25)])])}]]);export{s as __pageData,n as default};
